#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        long long max_happiness = 0;
        for (int i = 0; i < N; i++) {
            max_happiness += (i + 1) * (long long)A[i];
        }
        printf("%lld\n", max_happiness);
    }
    return 0;
}

